export const isMacOSTest = ({ userAgent }) => {
    return /(macintosh|macintel|macppc|mac68k|macos)/i.test(userAgent);
};
export const isiOSTest = ({ userAgent }) => {
    return /(iphone|ipad|ipod)/i.test(userAgent);
};
export const isWindowsOSTest = ({ userAgent }) => {
    return /(win32|win64|windows)/i.test(userAgent);
};
export const isAndroidOSTest = ({ userAgent }) => {
    return /android/i.test(userAgent);
};
export const isMacOS = !import.meta.env.SSR && isMacOSTest(navigator);
export const isWindowsOS = !import.meta.env.SSR && isWindowsOSTest(navigator);
export const isiOS = !import.meta.env.SSR && isiOSTest(navigator);
export const isAndroidOS = !import.meta.env.SSR && isAndroidOSTest(navigator);
